mapper.select:
/* VM_HR01A01_Dao_retrieveDeptCd */ WITH CONDITION_DEPT AS ( SELECT * FROM ( SELECT * FROM HRM.VM_HR01A01 WHERE SYSDATE BETWEEN STRDT AND ENDDT ) CONNECT BY NOCYCLE PRIOR OBJID = UPOBJ
START WITH OBJID = #{topDeptCd}
START WITH SEQNO = 1
UNION SELECT * FROM ( SELECT * FROM HRM.VM_HR01A01 WHERE SYSDATE BETWEEN STRDT AND ENDDT ) CONNECT BY NOCYCLE PRIOR UPOBJ = OBJID
START WITH OBJID = #{topDeptCd}
START WITH SEQNO = 1
) SELECT LEVEL AS LEV, OBJID, STEXT, REGDT, UPDDT, ZFCOD, STRDT, ENDDT, UPOBJ, DEPTH, SEQNO, PARTS, DIVI1, DIVI2, PERNR, KOSTL FROM CONDITION_DEPT
AND LEVEL <= #{orgchtDp}
CONNECT BY NOCYCLE PRIOR OBJID = UPOBJ START WITH SEQNO = 1

/* VM_HR01A01_Dao_retrieveDeptList */ WITH CONDITION_DEPT AS ( SELECT * FROM ( SELECT * FROM HRM.VM_HR01A01 WHERE SYSDATE BETWEEN STRDT AND ENDDT ) CONNECT BY NOCYCLE PRIOR OBJID = UPOBJ
START WITH OBJID = #{tplvlObjid}
START WITH OBJID = #{topDeptCd}
START WITH SEQNO = 1
UNION SELECT * FROM ( SELECT * FROM HRM.VM_HR01A01 WHERE SYSDATE BETWEEN STRDT AND ENDDT ) CONNECT BY NOCYCLE PRIOR UPOBJ = OBJID
START WITH OBJID = #{tplvlObjid}
START WITH OBJID = #{topDeptCd}
START WITH SEQNO = 1
) SELECT OBJID, STEXT, REGDT, UPDDT, ZFCOD, STRDT, ENDDT, UPOBJ, DEPTH, SEQNO, PARTS, DIVI1, DIVI2, PERNR, KOSTL FROM CONDITION_DEPT
AND LEVEL <= #{orgchtDp}
AND OBJID = #{objid}
AND OBJID IN ( SELECT OBJID FROM CONDITION_DEPT CONNECT BY NOCYCLE PRIOR OBJID= UPOBJ START WITH OBJID = #{tplvlObjid} )
AND STEXT LIKE '%' || #{stext} || '%'
CONNECT BY NOCYCLE PRIOR OBJID = UPOBJ START WITH SEQNO = 1 -- ORDER BY STEXT
